import React, { useState } from "react";
import { api } from "../api";
import { useNavigate } from "react-router-dom";

export default function AddInvestor() {
  const [form, setForm] = useState({ name: "", phone: "", img: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  function onChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  async function onSubmit(e) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      await api.post("/investors", form);
      navigate("/investors");
    } catch (err) {
      setError("Failed to add investor");
    }
    setLoading(false);
  }

  return (
    <div>
      <h2>Add Investor</h2>
      <form onSubmit={onSubmit}>
        <div>
          <label>Name</label>
          <input name="name" value={form.name} onChange={onChange} required />
        </div>
        <div>
          <label>Phone</label>
          <input name="phone" value={form.phone} onChange={onChange} required />
        </div>
        <div>
          <label>Image URL</label>
          <input name="img" value={form.img} onChange={onChange} />
        </div>
        {error && <div style={{ color: "red" }}>{error}</div>}
        <button type="submit" disabled={loading}>
          {loading ? "Saving..." : "Add Investor"}
        </button>
      </form>
    </div>
  );
}
